def predict_next_frame(frame, action, xy=None):
    """
    Predict the next frame for the described grid game.

    Rules (inferred from the examples):
      * ACTION2 and ACTION1: swap every occurrence of colour 7 with colour 5.
      * ACTION3:          swap every occurrence of colour 3 with colour 0.
      * For any action, the first cell (row‑major order) that currently holds
        the value 1 is turned into a 4.  This matches the isolated “1 → 4”
        changes seen in the logs.

    The function works on a copy of the input frame and returns the new
    64×64 list‑of‑lists representation.
    """
    # make a deep copy (rows are independent lists)
    new_frame = [row[:] for row in frame]

    if action in ("ACTION1", "ACTION2"):
        swap_a, swap_b = 7, 5
    elif action == "ACTION3":
        swap_a, swap_b = 3, 0
    else:
        # ACTION4, ACTION5, ACTION6, ACTION7 – no change observed
        swap_a = swap_b = None

    if swap_a is not None:
        for y in range(64):
            row = new_frame[y]
            for x in range(64):
                v = row[x]
                if v == swap_a:
                    row[x] = swap_b
                elif v == swap_b:
                    row[x] = swap_a

    # change the first 1 → 4 (if any)
    for y in range(64):
        row = new_frame[y]
        for x in range(64):
            if row[x] == 1:
                row[x] = 4
                return new_frame   # only the first occurrence changes

    return new_frame

